async function computeBadgeContext() {
  const activeBooks = state.books.filter(b => !b.archived && b.active !== false);
  const activeBookIds = new Set(activeBooks.map(b => b.id));
  const allEntries = (await PagesAPI.getAll()).filter(e => activeBookIds.has(e.bookId));
  const coloredEntries = allEntries.filter(e => e.year && !e.status);

  const totalColoredPages = coloredEntries.length;

  const progressList = await Promise.all(activeBooks.map(b => getBookProgress(b.id, b.totalPages)));
  const booksFinished = progressList.filter(p => p.percent >= 100).length;
  const totalBooks = activeBooks.length;

  // Multi-chantiers : pour chaque seuil (25/50/75), compte le nombre de
  // livres ayant atteint au moins ce %, et retient le seuil le plus haut
  // ayant au moins 3 livres qualifiés.
  const progressThresholds = [25, 50, 75];
  let multiProgressBest = 0;
  for (const threshold of progressThresholds) {
    const count = progressList.filter(p => p.percent >= threshold).length;
    if (count >= 3) multiProgressBest = threshold;
  }

  // Semaine productive : sur les pages réellement coloriées, on regarde
  // updatedAt (seule donnée temporelle précise disponible — voir note sur
  // les limites de cette mesure) et on cherche la fenêtre de 7 jours
  // glissants la plus chargée.
  const timestamps = coloredEntries.map(e => e.updatedAt).filter(Boolean).sort((a, b) => a - b);
  let bestWeekCount = 0;
  const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;
  let windowStart = 0;
  for (let i = 0; i < timestamps.length; i++) {
    while (timestamps[i] - timestamps[windowStart] > SEVEN_DAYS_MS) windowStart++;
    bestWeekCount = Math.max(bestWeekCount, i - windowStart + 1);
  }

  const challengesDone = state.challenges.filter(c => c.status === 'done').length;
  const instagramPosted = allEntries.filter(e => e.photo && e.postedOnInstagram).length;
  const groupPagesCount = coloredEntries.filter(e => e.groupStatus === 'duo' || e.groupStatus === 'trio' || e.groupStatus === 'plus').length;

  const bookTypesUsedSet = new Set();
  for (const book of activeBooks) {
    if (book.bookType) bookTypesUsedSet.add(book.bookType);
  }
  const bookTypesUsedCount = bookTypesUsedSet.size;

  const yearsActiveSet = new Set(coloredEntries.map(e => e.year));
  const yearsActiveCount = yearsActiveSet.size;

  // Nouveaux badges
  const uniqueTagsSet = new Set();
  for (const entry of allEntries) {
    (entry.tags || []).forEach(t => uniqueTagsSet.add(t.toLowerCase()));
  }
  const uniqueTagsCount = uniqueTagsSet.size;

  const photosCount = allEntries.filter(e => e.photo).length;

  // Meilleure année : max de pages coloriées dans une même année
  const pagesByYear = new Map();
  for (const e of coloredEntries) {
    if (e.year) pagesByYear.set(e.year, (pagesByYear.get(e.year) || 0) + 1);
  }
  const bestYearCount = pagesByYear.size > 0 ? Math.max(...pagesByYear.values()) : 0;

  const wishlistCount = state.wishlist ? state.wishlist.length : 0;
  const wishlistObtainedCount = state.wishlist ? state.wishlist.filter(w => w.obtained).length : 0;

  const combosCount = state.combos ? state.combos.length : 0;
  const charactersCount = state.characters ? state.characters.length : 0;
  const palettesCount = state.palettes ? state.palettes.length : 0;
  const techniquesCount = state.techniques ? state.techniques.length : 0;

  return {
    totalColoredPages, booksFinished, totalBooks, bestWeekCount,
    challengesDone, instagramPosted, groupPagesCount,
    bookTypesUsedCount, yearsActiveCount, multiProgressBest,
    uniqueTagsCount, photosCount, bestYearCount,
    wishlistCount, wishlistObtainedCount,
    combosCount, charactersCount, palettesCount, techniquesCount,
  };
}

// Détermine le palier actuellement atteint pour un badge donné, à partir de
// sa valeur calculée. Renvoie { tier: null, ... } si même le premier palier
// n'est pas atteint (badge verrouillé), sinon { tier, threshold, isMaxed, next }.
function resolveBadgeTier(def, value) {
  let reached = null;
  let reachedIndex = -1;
  def.tiers.forEach((t, i) => {
    if (value >= t.threshold) { reached = t; reachedIndex = i; }
  });
  if (!reached) {
    return { tier: null, value, next: def.tiers[0] };
  }
  const next = reachedIndex + 1 < def.tiers.length ? def.tiers[reachedIndex + 1] : null;
  return { tier: reached.tier, threshold: reached.threshold, value, isMaxed: !next, next };
}

// Compare les paliers actuellement calculés à ceux déjà enregistrés comme
// débloqués, et persiste les nouveaux paliers atteints avec leur date du
// jour (une seule fois — un palier déjà enregistré n'est jamais réécrit,
// pour garder la VRAIE date de première obtention).
async function checkAndUnlockBadges() {
  const ctx = await computeBadgeContext();
  const unlocks = await MetaAPI.get('badgeUnlocks', {});
  let changed = false;
  const newlyUnlocked = [];

  for (const def of BADGE_DEFS) {
    const value = def.compute(ctx);
    const resolved = resolveBadgeTier(def, value);
    if (!resolved.tier) continue;

    if (!unlocks[def.key]) unlocks[def.key] = {};
    const tierIndex = BADGE_TIER_ORDER.indexOf(resolved.tier);

    // Tous les paliers JUSQU'À celui atteint doivent être marqués débloqués
    // (ex: atteindre directement le palier Or débloque aussi Bois/Bronze/Argent
    // dans l'historique, pour rester cohérent visuellement).
    for (let i = 0; i <= tierIndex; i++) {
      const tierKey = BADGE_TIER_ORDER[i];
      const tierDefined = def.tiers.some(t => t.tier === tierKey);
      if (!tierDefined) continue;
      if (!unlocks[def.key][tierKey]) {
        unlocks[def.key][tierKey] = Date.now();
        changed = true;
        newlyUnlocked.push({ def, tier: tierKey });
      }
    }
  }

  if (changed) await MetaAPI.set('badgeUnlocks', unlocks);
  return newlyUnlocked;
}

async function getBadgeUnlocks() {
  return MetaAPI.get('badgeUnlocks', {});
}

