async function updateMissionNotifDot() {
  const missions = await getMissions();
  const active = missions.filter(m => !m.completedAt);
  if (!active.length) {
    const dot = document.getElementById('mission-notif-dot');
    if (dot) dot.hidden = true;
    return;
  }
  // N'afficher le point bleu que si une nouvelle mission est arrivée depuis la dernière visite
  const lastSeen = await MetaAPI.get('missionsLastSeen', 0);
  const hasNew = active.some(m => m.createdAt > lastSeen);
  const dot = document.getElementById('mission-notif-dot');
  if (dot) dot.hidden = !hasNew;
}

// Incrémenter la progression des missions d'un type donné
async function progressMission(type, amount = 1) {
  const missions = await getMissions();
  const active = missions.filter(m => !m.completedAt && m.type === type);
  if (!active.length) return;
  for (const mission of active) {
    mission.progress = (mission.progress || 0) + amount;
    await saveMission(mission);
    if (mission.progress >= mission.target) {
      showToast(`🎯 Mission accomplie : ${mission.label} ! Va la réclamer dans l'onglet Badges.`);
    }
  }
  updateMissionNotifDot();
}

function formatTimeLeft(lastPopTime) {
  const DELAY_72H = 72 * 60 * 60 * 1000;
  const elapsed = Date.now() - lastPopTime;
  const left = Math.max(0, DELAY_72H - elapsed);
  if (left === 0) return null;
  const h = Math.floor(left / 3600000);
  const m = Math.floor((left % 3600000) / 60000);
  if (h > 0) return `${h}h ${m}min`;
  return `${m}min`;
}

function renderMissionCard(mission) {
  const rarity = COLLECTION_RARITIES[mission.rewardRarity];
  const badge = COLLECTION_BADGES.find(b => b.key === mission.rewardBadgeKey);
  const progress = Math.min(mission.progress || 0, mission.target);
  const pct = Math.round((progress / mission.target) * 100);
  const done = progress >= mission.target;
  return `
    <div class="mission-card ${done ? 'mission-card--done' : ''}">
      <div class="mission-card__body">
        <div class="mission-card__label">${escapeHtml(mission.label)}</div>
        <div class="mission-card__desc">${escapeHtml(mission.desc)}</div>
        <div class="mission-card__progress">
          <div class="mission-card__bar"><div class="mission-card__fill" style="width:${pct}%"></div></div>
          <span class="mission-card__count">${progress}/${mission.target}</span>
        </div>
      </div>
      <div class="mission-card__reward">
        <img src="${badge?.img || ''}" class="mission-card__badge" alt="" style="${done ? '' : 'filter:grayscale(0.4)'}">
        <span style="color:${rarity.color};font-size:11px;font-weight:700">${rarity.emoji} ${escapeHtml(rarity.label)}</span>
        ${done
          ? `<button class="btn btn--primary btn--sm mission-card__claim" data-mission-id="${escapeHtml(mission.id)}">Réclamer !</button>`
          : `<button class="btn btn--ghost btn--sm mission-card__abandon" data-mission-id="${escapeHtml(mission.id)}" title="Abandonner cette mission">✕ Abandonner</button>`
        }
      </div>
    </div>`;
}

async function renderGalleryBadgesWithCollection(content) {
  await migrateMissionSlots();
  const missions = await getMissions();
  const active = missions.filter(m => !m.completedAt);
  const collection = await MetaAPI.get('badgeCollection', {});
  const missionsEnabled = await MetaAPI.get('missionsEnabled', true);

  const slots = await getMissionSlots();
  const DELAY_72H = 72 * 60 * 60 * 1000;

  const missSection = document.createElement('div');
  missSection.className = 'collection-section';

  // Construire les 3 slots visuels
  // Chaque slot affiche sa mission active, son timer, ou "disponible"
  const usedSlotIds = new Set(active.map(m => m.slotIndex).filter(s => s !== undefined));
  const slotsHtml = [0, 1, 2].map(i => {
    // Mission active sur ce slot ?
    let missionInSlot = active.find(m => m.slotIndex === i);
    // Fallback : missions sans slotIndex assigné, dans l'ordre
    if (!missionInSlot) {
      const unassigned = active.filter(m => m.slotIndex === undefined);
      if (i - usedSlotIds.size < unassigned.length) missionInSlot = unassigned[i - usedSlotIds.size];
    }
    if (missionInSlot) return renderMissionCard(missionInSlot);

    // Timer ?
    const closedAt = slots[i];
    if (closedAt !== undefined) {
      const left = Math.max(0, DELAY_72H - (Date.now() - closedAt));
      if (left > 0) {
        const h = Math.floor(left / 3600000);
        const m2 = Math.floor((left % 3600000) / 60000);
        const timeStr = h > 0 ? `${h}h ${m2}min` : `${m2}min`;
        return `<div class="mission-slot-timer">
          <span class="mission-slot-timer__icon">⏱</span>
          <span>Nouvelle mission dans <b>${timeStr}</b></span>
        </div>`;
      }
    }
    return `<div class="mission-slot-empty">🎯 Slot disponible — une mission peut arriver bientôt !</div>`;
  }).join('');

  missSection.innerHTML = `
    <div class="collection-section__header">
      <h3 class="collection-section__title">🎯 Missions</h3>
      <div style="display:flex;gap:8px;align-items:center;">
        <button class="btn btn--ghost btn--sm" id="btn-force-mission">+ Forcer mission</button>
        <label class="tag-multi-toggle">
          <input type="checkbox" id="toggle-missions" ${missionsEnabled ? 'checked' : ''}>
          <span class="tag-multi-toggle__track"><span class="tag-multi-toggle__thumb"></span></span>
          <span class="tag-multi-toggle__label">${missionsEnabled ? 'Activées' : 'Désactivées'}</span>
        </label>
      </div>
    </div>
    ${slotsHtml}`;

  missSection.querySelector('#toggle-missions').addEventListener('change', async (e) => {
    await MetaAPI.set('missionsEnabled', e.target.checked);
    e.target.nextElementSibling.nextElementSibling.textContent = e.target.checked ? 'Activées' : 'Désactivées';
  });

  missSection.querySelector('#btn-force-mission').addEventListener('click', async () => {
    await tryPopMission();
    renderGalleryContent();
  });

  missSection.querySelectorAll('.mission-card__claim').forEach(btn => {
    btn.addEventListener('click', async () => {
      await completeMission(btn.dataset.missionId);
      renderGalleryContent();
    });
  });

  missSection.querySelectorAll('.mission-card__abandon').forEach(btn => {
    btn.addEventListener('click', async () => {
      const missions2 = await getMissions();
      const m = missions2.find(x => x.id === btn.dataset.missionId);
      if (m) await setMissionSlot(m.slotIndex ?? 0, Date.now());
      await deleteMission(btn.dataset.missionId);
      showToast('Mission abandonnée — ce slot sera disponible dans 72h.');
      renderGalleryContent();
    });
  });

  const colSection = document.createElement('div');
  colSection.className = 'collection-section';
  colSection.innerHTML = `
    <div class="collection-section__header">
      <h3 class="collection-section__title">✨ Collection de badges</h3>
      <span class="collection-section__count">${Object.keys(collection).length} / ${COLLECTION_BADGES.length}</span>
    </div>
    <div class="collection-grid">
      ${COLLECTION_BADGES.map(badge => {
        const owned = collection[badge.key];
        const rarity = COLLECTION_RARITIES[badge.rarity];
        return `<div class="collection-badge ${owned ? 'collection-badge--owned' : 'collection-badge--locked'}"
          title="${escapeHtml(badge.label)} — ${escapeHtml(rarity.label)}">
          <div class="collection-badge__img-wrap" style="border-color:${owned ? rarity.color : '#555'}">
            <img src="${badge.img}" alt="" style="${owned ? '' : 'filter:grayscale(1) brightness(0.3)'}">
          </div>
          <div class="collection-badge__label" style="color:${owned ? rarity.color : 'var(--ink-faint)'}">
            ${owned ? rarity.emoji : '🔒'} ${escapeHtml(badge.label)}
          </div>
        </div>`;
      }).join('')}
    </div>`;

  content.innerHTML = '';
  const badgesDiv = document.createElement('div');
  badgesDiv.className = 'badge-rows';
  renderBadgeRowsAsync(badgesDiv);
  content.appendChild(badgesDiv);
  content.appendChild(missSection);
  content.appendChild(colSection);
}


