/* ---------- COULEUR D'ACCENT PERSONNALISABLE ---------- */

const DEFAULT_ACCENT_COLOR = '#D88C5A';

function darkenHexColor(hex, amount = 0.16) {
  // Assombrit une couleur hex d'un pourcentage donné, pour dériver
  // automatiquement la variante "hover/deep" à partir de la seule teinte
  // choisie par l'utilisateur — sans lui demander de régler 2 couleurs.
  const clean = hex.replace('#', '');
  const r = parseInt(clean.substring(0, 2), 16);
  const g = parseInt(clean.substring(2, 4), 16);
  const b = parseInt(clean.substring(4, 6), 16);
  const darken = (c) => Math.max(0, Math.round(c * (1 - amount)));
  const toHex = (c) => c.toString(16).padStart(2, '0');
  return `#${toHex(darken(r))}${toHex(darken(g))}${toHex(darken(b))}`;
}

function applyAccentColor(hex) {
  document.documentElement.style.setProperty('--accent-terracotta', hex);
  document.documentElement.style.setProperty('--accent-terracotta-deep', darkenHexColor(hex));
}

async function initAccentColor() {
  const saved = await MetaAPI.get('accentColor', null);
  const color = saved || DEFAULT_ACCENT_COLOR;
  applyAccentColor(color);
  const picker = document.getElementById('accent-color-picker');
  if (picker) picker.value = color;
}

async function initStatsColorOverrides() {
  const saved = await MetaAPI.get('statsColorOverrides', null);
  // Reconstruction défensive de la structure complète : si "saved" vient
  // d'une session précédente avec un format partiel ou incorrect (ex:
  // certaines clés manquantes, ou — bug découvert après coup — une chaîne
  // de caractères stockée là où un TABLEAU est attendu pour topTagsBar/
  // recapBooksBar/recapTopTagsBar), on reconstruit proprement plutôt que
  // de garder une structure invalide. Une chaîne comme '#f2c4a6' passerait
  // le test "saved.topTagsBar || []" car elle est "truthy" en JS, mais
  // ensuite tout assignation par INDEX dessus (state...[kind][index] = ..)
  // échouerait SILENCIEUSEMENT sans aucune erreur — exactement ce qui
  // faisait que rien ne se sauvegardait jamais pour ces deux groupes.
  state.statsColorOverrides = {
    bookTypes: (saved && saved.bookTypes) || {},
    progressBuckets: (saved && saved.progressBuckets) || {},
    topTagsBar: Array.isArray(saved && saved.topTagsBar) ? saved.topTagsBar : [],
    recapBooksBar: Array.isArray(saved && saved.recapBooksBar) ? saved.recapBooksBar : [],
    recapTopTagsBar: Array.isArray(saved && saved.recapTopTagsBar) ? saved.recapTopTagsBar : [],
  };
  // Nettoyage défensif : si une session précédente a enregistré des
  // valeurs corrompues (un seul caractère au lieu d'un vrai #rrggbb, suite
  // à un événement anormal sur le sélecteur de couleur), on les retire
  // silencieusement plutôt que de continuer à les afficher/réutiliser.
  let hadCorruption = false;
  for (const key of Object.keys(state.statsColorOverrides.bookTypes)) {
    if (!isValidHexColor(state.statsColorOverrides.bookTypes[key])) {
      delete state.statsColorOverrides.bookTypes[key];
      hadCorruption = true;
    }
  }
  for (const key of Object.keys(state.statsColorOverrides.progressBuckets)) {
    if (!isValidHexColor(state.statsColorOverrides.progressBuckets[key])) {
      delete state.statsColorOverrides.progressBuckets[key];
      hadCorruption = true;
    }
  }
  for (const arrKey of ['topTagsBar', 'recapBooksBar', 'recapTopTagsBar']) {
    const arr = state.statsColorOverrides[arrKey] || [];
    for (let i = 0; i < arr.length; i++) {
      if (arr[i] != null && !isValidHexColor(arr[i])) {
        arr[i] = null;
        hadCorruption = true;
      }
    }
  }
  if (hadCorruption) {
    await saveStatsColorOverrides();
  }
}

async function saveStatsColorOverrides() {
  await MetaAPI.set('statsColorOverrides', state.statsColorOverrides);
}

async function handleAccentColorChange(e) {
  const hex = e.target.value;
  applyAccentColor(hex);
  await MetaAPI.set('accentColor', hex);
}

async function handleResetAccentColor() {
  applyAccentColor(DEFAULT_ACCENT_COLOR);
  await MetaAPI.set('accentColor', DEFAULT_ACCENT_COLOR);
  const picker = document.getElementById('accent-color-picker');
  if (picker) picker.value = DEFAULT_ACCENT_COLOR;
  closeDropdownMenu();
}

