async function refreshTagUsageFrequency() {
  // Calculée une fois ici plutôt qu'à chaque frappe dans une barre de
  // recherche : avec beaucoup de tags, refaire le calcul à chaque lettre
  // tapée serait inutilement coûteux pour un résultat qui ne change pas
  // entre deux frappes consécutives.
  const freq = new Map();
  for (const book of state.books) {
    for (const tag of (book.tags || [])) freq.set(tag, (freq.get(tag) || 0) + 1);
  }
  const allEntries = await PagesAPI.getAll();
  for (const entry of allEntries) {
    for (const tag of (entry.tags || [])) freq.set(tag, (freq.get(tag) || 0) + 1);
  }
  state.tagUsageFrequency = freq;
}

