async function showFavoritesGalleryView() {
  hideAllViews();
  document.getElementById('view-favorites-gallery').hidden = false;

  await checkAndUnlockBadgesWithNotif();

  // Pastille rouge (badge) → onglet Badges
  // Pastille bleue (mission) → onglet Badges section missions
  // Les deux → onglet Badges (badges en priorité)
  const badgeDot = document.getElementById('badge-notif-dot');
  const missionDot = document.getElementById('mission-notif-dot');
  const hasBadgeNotif = badgeDot && !badgeDot.hidden;
  const hasMissionNotif = missionDot && !missionDot.hidden;

  if (hasBadgeNotif || hasMissionNotif) {
    state.gallerySection = 'badges';
  }

  await buildGallerySections();
  renderGalleryTabs();
  renderGalleryContent();

  // Scroll vers le badge qui scintille
  if (hasBadgeNotif) {
    setTimeout(() => {
      const shining = document.querySelector('.medal-wrap--new');
      if (shining) shining.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 300);
  } else if (hasMissionNotif) {
    // Scroll vers la section missions
    setTimeout(() => {
      const missSection = document.querySelector('.collection-section');
      if (missSection) missSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 300);
  }
}

function renderGalleryTabs() {
  const tabsContainer = document.getElementById('gallery-tabs');

  // Ordre fixe : Musée toujours premier, "Livre de coloriage" toujours
  // deuxième, puis chaque Type de livre créé par l'utilisateur dans son
  // ordre de création exact (state.bookTypes est déjà trié par sortIndex)
  // — un nouveau type créé apparaît donc automatiquement à la suite, sans
  // toucher à ce code.
  const tabs = [
    { key: 'museum', label: 'Musée' },
    { key: 'badges', label: 'Badges' },
    { key: 'wall',   label: 'Mur' },
    { key: 'noType', label: 'Livre de coloriage' },
    ...state.bookTypes.map(bt => ({ key: bt.id, label: bt.name })),
  ];

  // Si la section actuellement sélectionnée n'existe plus (ex: son type a
  // été supprimé entre deux visites), on retombe sur Musée par défaut.
  if (!tabs.some(t => t.key === state.gallerySection)) {
    state.gallerySection = 'museum';
  }

  tabsContainer.innerHTML = tabs.map(t => `
    <button class="toolbar-tab ${t.key === state.gallerySection ? 'is-active' : ''}" data-gallery-section="${t.key}" type="button" role="tab" aria-selected="${t.key === state.gallerySection}">${escapeHtml(t.label)}</button>
  `).join('');

  tabsContainer.querySelectorAll('[data-gallery-section]').forEach(btn => {
    btn.addEventListener('click', () => {
      state.gallerySection = btn.dataset.gallerySection;
      state.galleryIndex = 0;
      tabsContainer.querySelectorAll('[data-gallery-section]').forEach(b => {
        const isActive = b === btn;
        b.classList.toggle('is-active', isActive);
        b.setAttribute('aria-selected', String(isActive));
      });
      renderGalleryContent();
    });
  });
}

async function buildGallerySections() {
  const allEntries = await PagesAPI.getAll();
  const entriesByBookId = new Map();
  for (const e of allEntries) {
    if (!e.photo || !e.year || e.status) continue; // seulement les vraies pages coloriées avec photo
    if (!entriesByBookId.has(e.bookId)) entriesByBookId.set(e.bookId, []);
    entriesByBookId.get(e.bookId).push(e);
  }

  // Une double page fusionnée partage la même photo sur ses deux numéros
  // de page — on exclut la "seconde" pour ne jamais l'afficher deux fois
  // de suite dans la séquence, même logique que pour le carrousel du haut.
  for (const book of state.books) {
    const pairs = book.mergedPagePairs || [];
    if (pairs.length === 0) continue;
    const entries = entriesByBookId.get(book.id);
    if (!entries) continue;
    const excludedPageNumbers = new Set(pairs.map(([a, b]) => Math.max(a, b)));
    entriesByBookId.set(book.id, entries.filter(e => !excludedPageNumbers.has(e.pageNumber)));
  }

  // Répartition par TYPE DE LIVRE réel (state.bookTypes, créé par
  // l'utilisateur) — plus aucun onglet codé en dur ici. Un livre sans type
  // assigné retombe dans "Livre de coloriage".
  const booksByTypeId = new Map(); // bookTypeId -> [{ book, entries }]
  const noTypeBooks = [];

  for (const book of state.books) {
    if (book.archived) continue;
    const entries = entriesByBookId.get(book.id);
    if (!entries || entries.length === 0) continue; // un livre sans aucune page colorée+photo n'a rien à montrer
    entries.sort((a, b) => a.pageNumber - b.pageNumber);
    if (book.bookType) {
      if (!booksByTypeId.has(book.bookType)) booksByTypeId.set(book.bookType, []);
      booksByTypeId.get(book.bookType).push({ book, entries });
    } else {
      noTypeBooks.push({ book, entries });
    }
  }

  // Mélange aléatoire des LIVRES (pas des pages à l'intérieur, qui restent
  // dans l'ordre de la numérotation) — à chaque ouverture de la galerie.
  function shuffleInPlace(arr) {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
  }
  for (const list of booksByTypeId.values()) shuffleInPlace(list);
  shuffleInPlace(noTypeBooks);

  // Construit la séquence "page de présentation, puis pages du livre par
  // paires" pour un onglet en mode Livre — la page de présentation embarque
  // désormais aussi l'avancement complet du livre (déjà calculé une seule
  // fois ici, pour rester une fonction de rendu synchrone côté affichage).
  async function buildBookModeSequence(booksList) {
    const sequence = [];
    for (const { book, entries } of booksList) {
      const progress = await getBookProgress(book.id, book.totalPages);
      sequence.push({ type: 'cover', book, progress });
      for (const entry of entries) {
        sequence.push({ type: 'page', book, entry });
      }
    }
    return sequence;
  }

  // Ordre final des onglets : Musée (géré séparément), puis "Livre de
  // coloriage", puis chaque Type de livre dans son ordre de création exact
  // (state.bookTypes est déjà trié par sortIndex) — un nouveau type créé
  // par l'utilisateur apparaît donc automatiquement ici, à la suite.
  state.gallerySections = {};
  state.gallerySections.noType = await buildBookModeSequence(noTypeBooks);
  for (const bt of state.bookTypes) {
    state.gallerySections[bt.id] = await buildBookModeSequence(booksByTypeId.get(bt.id) || []);
  }

  // Section Musée : reprend la logique des favoris déjà existante.
  const favoriteEntries = await PagesAPI.getAllFavorites();
  const museumItems = [];
  for (const entry of favoriteEntries) {
    const book = state.books.find(b => b.id === entry.bookId);
    if (book) museumItems.push({ entry, book });
  }
  shuffleInPlace(museumItems);
  state.gallerySections.museum = museumItems;
}

/* ---------- CARROUSEL "VIVANT" DE PHOTOS ---------- */

function shuffleArrayDeterministic(arr, seedString) {
  // Mélange Fisher-Yates piloté par une graine numérique dérivée de la
  // chaîne fournie : le même contenu (même seedString) donne toujours le
  // même ordre mélangé — utile pour éviter que le carrousel ne se
  // réorganise visuellement à chaque rafraîchissement sans rapport.
  let seed = 0;
  for (let i = 0; i < seedString.length; i++) {
    seed = (seed * 31 + seedString.charCodeAt(i)) % 2147483647;
  }
  function nextRandom() {
    seed = (seed * 16807) % 2147483647;
    return seed / 2147483647;
  }
  const result = [...arr];
  for (let i = result.length - 1; i > 0; i--) {
    const j = Math.floor(nextRandom() * (i + 1));
    [result[i], result[j]] = [result[j], result[i]];
  }
  return result;
}

async function refreshPhotoCarousel() {
  const allEntries = await PagesAPI.getAll();
  // Livres actifs (non archivés ET active !== false)
  const activeBookIds = new Set(state.books.filter(b => !b.archived && b.active !== false).map(b => b.id));

  // Pour chaque double page fusionnée, les deux pages partagent la même
  // photo : on ne garde que la première des deux dans le carrousel pour
  // éviter d'afficher deux fois la même image à la suite.
  const secondPageOfPairByBook = new Map(); // bookId -> Set des numéros de page "seconde" à exclure
  for (const book of state.books) {
    const pairs = book.mergedPagePairs || [];
    if (pairs.length === 0) continue;
    const excluded = new Set();
    for (const [a, b] of pairs) excluded.add(Math.max(a, b));
    secondPageOfPairByBook.set(book.id, excluded);
  }

  const withPhoto = allEntries.filter(e => {
    if (!e.photo) return false;
    if (!activeBookIds.has(e.bookId)) return false;
    const excluded = secondPageOfPairByBook.get(e.bookId);
    return !excluded || !excluded.has(e.pageNumber);
  });

  const track = document.getElementById('photo-carousel-track');

  if (withPhoto.length === 0) {
    document.getElementById('photo-carousel').hidden = true;
    return;
  }

  // Ordre mélangé plutôt que l'ordre naturel des livres — mais STABLE tant
  // que le contenu ne change pas vraiment, pour ne pas réordonner tout le
  // carrousel (et faire "sauter" visuellement les vignettes) à chaque
  // simple rafraîchissement sans rapport. On mélange une copie des entrées
  // une seule fois par contenu identique, via un hachage simple basé sur
  // les identifiants présents.
  const contentKey = withPhoto.map(e => `${e.bookId}-${e.pageNumber}`).sort().join('|');
  if (state.photoCarouselShuffleKey !== contentKey) {
    state.photoCarouselShuffleKey = contentKey;
    state.photoCarouselShuffledEntries = shuffleArrayDeterministic(withPhoto, contentKey);
  }
  const shuffled = state.photoCarouselShuffledEntries;

  // Le contenu est dupliqué une fois pour permettre une boucle de
  // défilement parfaitement continue (l'animation va de 0 à -50%, donc
  // la 2e copie prend exactement le relais de la 1ère sans saut visible).
  const thumbsHtml = shuffled.map(e => `<img class="photo-carousel__thumb" src="${e.photo}" alt="" loading="lazy">`).join('');
  track.innerHTML = thumbsHtml + thumbsHtml;

  // La durée est calculée à partir de la largeur RÉELLE mesurée du track
  // (pas d'une estimation approximative) : un écart, même petit, entre
  // la largeur estimée et la largeur réelle crée un décalage de vitesse
  // qui rend la jonction entre les deux copies visible comme un "à-coup",
  // pile l'effet de trou/saut signalé. requestAnimationFrame laisse le
  // temps au navigateur de poser les images avant de mesurer.
  requestAnimationFrame(() => {
    const halfWidth = track.scrollWidth / 2;
    const speedPxPerSecond = 40;
    const duration = Math.max(20, halfWidth / speedPxPerSecond);
    track.style.animationDuration = `${duration}s`;
  });
}

function updatePhotoCarouselVisibility() {
  const carousel = document.getElementById('photo-carousel');
  const galleryVisible = !document.getElementById('view-favorites-gallery').hidden;
  const hasContent = document.getElementById('photo-carousel-track').children.length > 0;
  carousel.hidden = galleryVisible || !hasContent;
}

function observeGalleryViewForCarousel() {
  // Plutôt que d'ajouter un appel à updatePhotoCarouselVisibility() dans
  // chacune des nombreuses fonctions show*View (risque d'en oublier une
  // à chaque nouvelle vue ajoutée plus tard), on observe directement
  // l'attribut "hidden" de TOUTES les vues — peu importe laquelle vient
  // de s'afficher ou de se masquer, le carrousel se replace au bon endroit.
  const observer = new MutationObserver(updatePhotoCarouselVisibility);
  document.querySelectorAll('main.view').forEach(view => {
    observer.observe(view, { attributes: true, attributeFilter: ['hidden'] });
  });
}

