function renderPaletteCard(palette) {
  const photo = palette.photo
    ? `<img src="${palette.photo}" alt="${escapeHtml(palette.name)}" class="palette-card__photo">`
    : `<div class="palette-card__photo palette-card__photo--empty"><svg class="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg></div>`;
  return `
    <div class="palette-card" data-palette-id="${palette.id}">
      ${photo}
      <div class="palette-card__name">${escapeHtml(palette.name)}</div>
      ${palette.notes ? `<div class="palette-card__notes">${escapeHtml(palette.notes)}</div>` : ''}
    </div>`;
}

function triggerRandomPalette(category) {
  const pool = category
    ? state.palettes.filter(p => (p.categories || [UNCATEGORIZED_CATEGORY]).includes(category))
    : state.palettes;
  if (!pool.length) { showToast('Aucune palette disponible.'); return; }
  const pick = pool[Math.floor(Math.random() * pool.length)];
  const resultEl = document.getElementById('palette-random-result');
  const inner = document.getElementById('palette-random-inner');
  inner.innerHTML = `
    <div class="palette-random-card">
      ${pick.photo ? `<img src="${pick.photo}" alt="${escapeHtml(pick.name)}" class="palette-random-card__photo">` : ''}
      <div class="palette-random-card__name">${escapeHtml(pick.name)}</div>
      ${pick.notes ? `<div class="palette-random-card__notes">${escapeHtml(pick.notes)}</div>` : ''}
    </div>`;
  resultEl.hidden = false;
  resultEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
  document.getElementById('btn-random-again').onclick = () => triggerRandomPalette(category);
  document.getElementById('btn-close-random').onclick = () => {
    resultEl.hidden = true;
    resultEl.style.display = '';
  };
}


