function renderTechniqueCard(tech) {
  const isYoutube = tech.url && (tech.url.includes('youtube.com') || tech.url.includes('youtu.be'));
  const videoId = isYoutube ? extractYoutubeId(tech.url) : null;
  const thumb = videoId ? `<img src="https://img.youtube.com/vi/${videoId}/mqdefault.jpg" alt="" class="technique-card__thumb">` : '';

  const linkBtn = tech.url
    ? `<a href="${escapeHtml(tech.url)}" target="_blank" rel="noopener" class="technique-card__link btn btn--secondary btn--sm">
        <svg class="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6M15 3h6v6M10 14 21 3"/></svg>
        Ouvrir
       </a>`
    : '';

  return `
    <div class="technique-card technique-card--${tech.type}" data-technique-id="${tech.id}">
      ${thumb}
      <div class="technique-card__body">
        <div class="technique-card__header">
          <span class="technique-card__type-badge">${tech.type === 'link' ? '🔗 Lien' : '📝 Note'}</span>
          <h3 class="technique-card__title">${escapeHtml(tech.title)}</h3>
        </div>
        ${tech.content ? `<p class="technique-card__content">${escapeHtml(tech.content)}</p>` : ''}
        ${linkBtn}
      </div>
    </div>`;
}

function extractYoutubeId(url) {
  const m = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
  return m ? m[1] : null;
}

// ─── MODALE PALETTE ────────────────────────────────────────────────────────

let pendingPalettePhoto = null;
let pendingPalettePhotoRemoved = false;
let editingPaletteId = null;
let pendingPaletteCategories = [];


function openPaletteModal(paletteId = null) {
  editingPaletteId = paletteId;
  pendingPalettePhoto = null;
  pendingPalettePhotoRemoved = false;
  const modal = document.getElementById('modal-palette');
  const titleEl = document.getElementById('modal-palette-title');
  const btnSave = document.getElementById('btn-save-palette');
  const btnDelete = document.getElementById('btn-delete-palette');
  const preview = document.getElementById('palette-photo-preview');
  const placeholder = document.querySelector('#palette-cover-uploader .cover-uploader__placeholder');
  const btnRemove = document.getElementById('btn-remove-palette-photo');
  document.getElementById('palette-warning').hidden = true;

  if (paletteId) {
    const p = state.palettes.find(x => x.id === paletteId);
    titleEl.textContent = 'Modifier la palette';
    btnSave.textContent = 'Enregistrer';
    btnDelete.hidden = false;
    document.getElementById('input-palette-name').value = p.name;
    document.getElementById('input-palette-notes').value = p.notes || '';
    pendingPaletteCategories = [...(p.categories || [UNCATEGORIZED_CATEGORY])];
    if (p.photo) {
      preview.src = p.photo; preview.hidden = false;
      placeholder.hidden = true; btnRemove.hidden = false;
    } else {
      preview.hidden = true; placeholder.hidden = false; btnRemove.hidden = true;
    }
  } else {
    titleEl.textContent = 'Nouvelle palette';
    btnSave.textContent = 'Ajouter la palette';
    btnDelete.hidden = true;
    document.getElementById('input-palette-name').value = '';
    document.getElementById('input-palette-notes').value = '';
    pendingPaletteCategories = [UNCATEGORIZED_CATEGORY];
    preview.hidden = true; placeholder.hidden = false; btnRemove.hidden = true;
  }
  renderGenericCategoryCheckboxes('palette');
  modal.hidden = false;
}

async function handlePaletteFormSubmit(e) {
  e.preventDefault();
  const name = document.getElementById('input-palette-name').value.trim();
  const notes = document.getElementById('input-palette-notes').value.trim();
  const warn = document.getElementById('palette-warning');
  if (!name) { warn.textContent = 'Merci de renseigner un nom.'; warn.hidden = false; return; }
  const categories = pendingPaletteCategories.length > 0 ? pendingPaletteCategories : [UNCATEGORIZED_CATEGORY];

  let photo;
  if (pendingPalettePhoto) photo = pendingPalettePhoto;
  else if (pendingPalettePhotoRemoved) photo = null;
  else photo = undefined;

  if (editingPaletteId) {
    const patch = { name, notes, categories };
    if (photo !== undefined) patch.photo = photo;
    await PalettesAPI.update(editingPaletteId, patch);
    showToast('Palette mise à jour.');
  } else {
    await PalettesAPI.create({ name, notes, photo: photo || null, categories });
    showToast('Palette ajoutée !');
    progressMission('palette');
  }
  await refreshPalettes();
  document.getElementById('modal-palette').hidden = true;
  renderPalettesView();
}

