/* ---------- MENU DÉROULANT : TIRAGE AU HASARD ---------- */

function toggleRandomPickMenu() {
  const menu = document.getElementById('random-pick-dropdown');
  const willOpen = menu.hidden;
  menu.hidden = !willOpen;
  if (willOpen) {
    document.addEventListener('click', handleOutsideRandomPickMenuClick, true);
  }
}

function closeRandomPickMenu() {
  document.getElementById('random-pick-dropdown').hidden = true;
  document.removeEventListener('click', handleOutsideRandomPickMenuClick, true);
}

function handleOutsideRandomPickMenuClick(e) {
  if (!e.target.closest('#random-pick-menu-wrap')) closeRandomPickMenu();
}

/* ---------- TIRAGE AU HASARD PONDÉRÉ ---------- */

function weightedRandomPick(items, getWeight) {
  // Tirage pondéré classique : chaque item a un "ticket" de loterie
  // proportionnel à son poids, et on pioche un point au hasard dans la
  // somme totale — un livre/page pas entamé (poids élevé) a donc bien
  // plus de chances de sortir qu'un livre déjà presque terminé, sans
  // pour autant être complètement exclu (poids jamais nul).
  const weights = items.map(getWeight);
  const total = weights.reduce((a, b) => a + b, 0);
  if (total <= 0) return items[Math.floor(Math.random() * items.length)];
  let roll = Math.random() * total;
  for (let i = 0; i < items.length; i++) {
    roll -= weights[i];
    if (roll <= 0) return items[i];
  }
  return items[items.length - 1];
}

async function handleRandomBookPick() {
  closeRandomPickMenu();
  const activeBooks = state.books.filter(b => !b.archived);
  if (activeBooks.length === 0) {
    showToast("Ajoute d'abord un livre à ta bibliothèque !");
    return;
  }
  const progressByBook = new Map(
    await Promise.all(activeBooks.map(async b => [b.id, await getBookProgress(b.id, b.totalPages)]))
  );
  // Un livre déjà à 100% est totalement exclu (pas juste défavorisé) :
  // il n'y a plus rien à colorier dedans, le tirer n'aurait pas de sens.
  const eligibleBooks = activeBooks.filter(b => (progressByBook.get(b.id)?.percent ?? 0) < 100);
  if (eligibleBooks.length === 0) {
    showToast('Tous tes livres sont déjà terminés, bravo !');
    return;
  }
  const picked = weightedRandomPick(eligibleBooks, (b) => 100 - progressByBook.get(b.id).percent);
  const progress = progressByBook.get(picked.id);
  openRandomPickResultModal({
    type: 'book',
    title: picked.title,
    subtitle: `${progress.percent}% colorié — ${progress.coloredCount}/${picked.totalPages} pages`,
    image: picked.cover || null,
    onGoTo: () => showBookDetailView(picked.id),
    onReroll: handleRandomBookPick,
  });
}

async function handleRandomPagePick(restrictToBookId = null) {
  closeRandomPickMenu();
  const candidateBooks = restrictToBookId
    ? state.books.filter(b => b.id === restrictToBookId)
    : state.books.filter(b => !b.archived);

  // Une page n'est éligible QUE si elle n'a vraiment pas encore été
  // coloriée (ni année/couleur, ni photo) et qu'elle n'est pas dans un état
  // qui la retire définitivement du jeu (ratée, Kévin, abandonnée) — "en
  // cours" reste éligible puisqu'elle attend encore d'être terminée.
  const EXCLUDED_STATUSES = ['failed', 'kevin', 'abandoned'];
  const allCandidates = [];
  for (const book of candidateBooks) {
    const entries = await PagesAPI.getForBook(book.id);
    const entryByPage = new Map(entries.map(e => [e.pageNumber, e]));
    for (let n = 1; n <= book.totalPages; n++) {
      const entry = entryByPage.get(n);
      if (entry && EXCLUDED_STATUSES.includes(entry.status)) continue; // jamais tirée
      const hasColorOrPhoto = !!(entry && (entry.year || entry.photo));
      const isInProgress = entry?.status === 'in_progress';
      const isEligible = !hasColorOrPhoto || isInProgress;
      if (isEligible) allCandidates.push({ book, pageNumber: n });
    }
  }

  if (allCandidates.length === 0) {
    showToast(restrictToBookId ? "Toutes les pages de ce livre sont déjà coloriées !" : "Toutes tes pages sont déjà coloriées !");
    return;
  }

  const picked = allCandidates[Math.floor(Math.random() * allCandidates.length)];
  openRandomPickResultModal({
    type: 'page',
    title: picked.book.title,
    subtitle: `Page ${picked.pageNumber} / ${picked.book.totalPages}`,
    image: picked.book.cover || null,
    onGoTo: () => showBookDetailView(picked.book.id, picked.pageNumber),
    onReroll: () => handleRandomPagePick(restrictToBookId),
  });
}

function openRandomPickResultModal({ title, subtitle, image, onGoTo, onReroll }) {
  let modal = document.getElementById('modal-random-pick-result');
  if (!modal) {
    modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.id = 'modal-random-pick-result';
    modal.innerHTML = `
      <div class="modal modal--small" role="dialog" aria-modal="true">
        <div class="modal__body" style="text-align:center; padding-top:28px;">
          <div class="random-pick-result__cover" id="random-pick-result-cover"></div>
          <h2 class="random-pick-result__title" id="random-pick-result-title"></h2>
          <p class="random-pick-result__subtitle" id="random-pick-result-subtitle"></p>
        </div>
        <div class="modal__footer" style="justify-content:center; gap:10px;">
          <button type="button" class="btn btn--secondary" id="btn-random-pick-reroll">🎲 Relancer</button>
          <button type="button" class="btn btn--primary" id="btn-random-pick-goto">Y aller</button>
        </div>
      </div>
    `;
    document.body.appendChild(modal);
    modal.addEventListener('click', (e) => { if (e.target === modal) modal.hidden = true; });
  }

  document.getElementById('random-pick-result-title').textContent = title;
  document.getElementById('random-pick-result-subtitle').textContent = subtitle;
  const coverEl = document.getElementById('random-pick-result-cover');
  coverEl.style.backgroundImage = image ? `url('${image}')` : '';
  coverEl.textContent = image ? '' : title;

  document.getElementById('btn-random-pick-reroll').onclick = () => { modal.hidden = true; onReroll(); };
  document.getElementById('btn-random-pick-goto').onclick = () => { modal.hidden = true; onGoTo(); };

  modal.hidden = false;
}

