/* ---------- EXPORT ---------- */

async function handleExportData() {
  closeDropdownMenu();
  try {
    const data = await BackupAPI.exportAll();
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const today = new Date().toISOString().slice(0, 10);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mes-coloriages-sauvegarde-${today}.json`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);

    showToast('Sauvegarde exportée.');
  } catch (err) {
    console.error(err);
    showToast("Erreur lors de l'export. Réessaie ou vérifie la console.", 'error');
  }
}

/* ---------- IMPORT ---------- */

let _pendingImportData = null;

function handleImportButtonClick() {
  closeDropdownMenu();
  document.getElementById('input-import-file').value = '';
  document.getElementById('input-import-file').click();
}

function handleImportFileChange(e) {
  const file = e.target.files[0];
  if (!file) return;

  const reader = new FileReader();
  reader.onload = () => {
    let data;
    try {
      data = JSON.parse(reader.result);
    } catch (err) {
      showToast("Ce fichier n'est pas un fichier de sauvegarde JSON valide.", 'error');
      return;
    }

    const requiredArrays = ['books', 'pageEntries', 'years', 'tags', 'challenges'];
    const missing = requiredArrays.filter(key => !Array.isArray(data[key]));
    if (missing.length > 0) {
      showToast("Ce fichier ne semble pas être une sauvegarde de Mes coloriages.", 'error');
      return;
    }

    _pendingImportData = data;
    const summary = `${data.books.length} livre${data.books.length !== 1 ? 's' : ''}, ${data.challenges.length} challenge${data.challenges.length !== 1 ? 's' : ''} et ${data.pageEntries.length} page${data.pageEntries.length !== 1 ? 's' : ''} suivie${data.pageEntries.length !== 1 ? 's' : ''}`;
    document.getElementById('import-summary-text').textContent = summary;
    document.getElementById('modal-import-confirm').hidden = false;
  };
  reader.onerror = () => showToast('Impossible de lire ce fichier.', 'error');
  reader.readAsText(file);
}

function closeImportConfirmModal() {
  document.getElementById('modal-import-confirm').hidden = true;
  _pendingImportData = null;
}

async function handleConfirmImport() {
  if (!_pendingImportData) return;
  try {
    await BackupAPI.importAll(_pendingImportData);
  } catch (err) {
    console.error(err);
    showToast(err.message || "Erreur lors de l'import.", 'error');
    closeImportConfirmModal();
    return;
  }

  closeImportConfirmModal();

  await refreshYears();
  await refreshTags();
  await refreshBooks();
  await refreshChallenges();
  showLibraryView();
  showToast('Sauvegarde importée avec succès.');
}

function showToast(message, type = 'success') {
  const container = document.getElementById('toast-container');
  const toast = document.createElement('div');
  toast.className = `toast toast--${type}`;
  toast.textContent = message;
  container.appendChild(toast);

  setTimeout(() => {
    toast.classList.add('is-leaving');
    setTimeout(() => toast.remove(), 200);
  }, 2600);
}

